patch:
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 245d0c4f073d..83011647a98f 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -8223,12 +8223,18 @@ static bool passingValueIsAlwaysUndefined(Value *V, Instruction *I, bool PtrValu
       if (CB->isArgOperand(&Use)) {
         unsigned ArgIdx = CB->getArgOperandNo(&Use);
         // Passing null to a nonnnull+noundef argument is undefined.
-        if (isa<ConstantPointerNull>(C) &&
-            CB->paramHasNonNullAttr(ArgIdx, /*AllowUndefOrPoison=*/false))
-          return !PtrValueMayBeModified;
+        if (isa<ConstantPointerNull>(C)) {
+          Type *ArgTy = CB->getArgOperand(ArgIdx)->getType();
+          if (ArgTy->isPointerTy() &&
+              CB->paramHasNonNullAttr(ArgIdx, /*AllowUndefOrPoison=*/false))
+            return !PtrValueMayBeModified;
+        }
         // Passing undef to a noundef argument is undefined.
-        if (isa<UndefValue>(C) && CB->isPassingUndefUB(ArgIdx))
-          return true;
+        if (isa<UndefValue>(C)) {
+          Type *ArgTy = CB->getArgOperand(ArgIdx)->getType();
+          if (ArgTy->isPointerTy() && CB->isPassingUndefUB(ArgIdx))
+            return true;
+        }
       }
     }
     // Div/Rem by zero is immediate UB

